@app.get("/widgets")
def list_widgets():
    q = request.args.get("q")
    with capture_span("sql:list_widgets", span_type="db", span_subtype="sql", span_action="select"):
        query = Widget.query
        if q:
            query = query.filter(Widget.name.contains(q))
        items = query.order_by(Widget.id.desc()).limit(100).all()
    return jsonify([{"id": w.id, "name": w.name, "created_at": w.created_at.isoformat()} for w in items])


